int join_line() {
  static int lineCount = 0; // 变量用于计数线的接触次数
  static unsigned long sensorCloseTime = 0; // 关闭传感器的时间

  digitalWrite(LED_PIN, true);

  if (lineCount == 0) { // 第一次接触到线时
    digitalWrite(SENSOR_PIN, LOW); // 关闭传感器
    sensorCloseTime = millis(); // 记录关闭传感器的时间
    lineCount++;
    return 0; // 返回0，表示继续前进
  } else if (lineCount == 1 && millis() - sensorCloseTime >= 1000) { // 第二次接触到线且距离关闭传感器的时间超过1秒
    digitalWrite(SENSOR_PIN, HIGH); // 打开传感器
    lineCount++;
    return 0; // 返回0，表示继续前进
  }

  // line found, turn on the spot to line up.
  while (abs(kinematics.Theta) < 40 * (3.14 / 180)) { // 原地转动直到达到40度，让机器人足够对齐线以便执行后续代码
    kinematics.update(); // 更新角度值
    motors.setMotorPower(25, -20); // 向右转，使左侧传感器先检测到线
  }

  return 2; // 一旦退出while循环，假设机器人已经在线上，返回2
}
```

在这个修改后的代码中，我们使用变量`sensorCloseTime`记录关闭传感器的时间。当`lineCount`为0，即第一次接触到线时，立即关闭传感器，并记录当前时间为`sensorCloseTime`。在`lineCount`为1且距离关闭传感器的时间超过1秒时，打开传感器。这样，机器人在第一次接触到线后立即关闭传感器，1秒后再重新打开传感器。之后，机器人会执行原地对齐的代码，并返回2表示机器人已经在线上。
